import React, { useState, useEffect, useRef } from 'react';
import Swal from 'sweetalert2';
import Chart from 'chart.js/auto';
import { Utils } from '../utils/helpers';
import { PlanilhaProcessor } from '../utils/api';
import { TABELA_PESOS, SERVICOS_IGNORADOS } from '../utils/constants';

const AbaProdutividade = () => {
  const [data, setData] = useState('');
  const [regionais, setRegionais] = useState({});
  const [tecnicosPlanilha, setTecnicosPlanilha] = useState([]);
  const [tecnicosSelecionados, setTecnicosSelecionados] = useState([]);
  const [buscaTermo, setBuscaTermo] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [dadosProdutividade, setDadosProdutividade] = useState([]);
  const [metricasAgregadas, setMetricasAgregadas] = useState({
    planejamento: 0,
    execucao: 0,
    remarcacao: 0,
    cancelamento: 0,
    tratativasCS: 0,
    infraestrutura: 0,
    resolucaoN2: 0,
    totalProdutividade: 0,
    totalExecutado: 0
  });
  const [filtroRegional, setFiltroRegional] = useState('todas');
  const [dadosPlanilha, setDadosPlanilha] = useState(null);

  // Refs para gráficos
  const barChartRef = useRef(null);
  const pieChartRef = useRef(null);
  const tecnicosChartRef = useRef(null);
  let barChartInstance = null;
  let pieChartInstance = null;
  let tecnicosChartInstance = null;

  // Carregar técnicos quando a data mudar
  useEffect(() => {
    const hoje = new Date().toISOString().split('T')[0];
    setData(hoje);
  }, []);

  useEffect(() => {
    if (data) {
      carregarTecnicosPorData(data);
    }
  }, [data]);

  const carregarTecnicosPorData = async (dataSelecionada) => {
    if (!dataSelecionada) return;

    setCarregando(true);
    setTecnicosSelecionados([]);
    setDadosProdutividade([]);
    setMetricasAgregadas({
      planejamento: 0,
      execucao: 0,
      remarcacao: 0,
      cancelamento: 0,
      tratativasCS: 0,
      infraestrutura: 0,
      resolucaoN2: 0,
      totalProdutividade: 0,
      totalExecutado: 0
    });

    try {
      const resposta = await PlanilhaProcessor.carregarDadosPorData(dataSelecionada);

      if (resposta.status === 'not_found' || !resposta.dados || resposta.dados.length === 0) {
        Swal.fire({
          icon: 'warning',
          title: 'Nenhum dado encontrado',
          text: `Nenhuma aba encontrada para ${Utils.formatarDataParaAba(dataSelecionada)}`,
          toast: true,
          timer: 3000
        });
        setRegionais({});
        setCarregando(false);
        return;
      }

      setDadosPlanilha(resposta.dados);

      let regionaisCarregadas = {};
      if (resposta.regionaisMap && Object.keys(resposta.regionaisMap).length > 0) {
        regionaisCarregadas = resposta.regionaisMap;
      } else {
        regionaisCarregadas = PlanilhaProcessor.extrairTecnicosPorRegional(resposta.dados);
      }

      setRegionais(regionaisCarregadas);

      // Extrair lista de técnicos com suas regionais
      const tecnicosList = [];
      for (let regional in regionaisCarregadas) {
        regionaisCarregadas[regional].forEach(tec => {
          tecnicosList.push({ nome: tec, regional });
        });
      }
      setTecnicosPlanilha(tecnicosList);

      Swal.fire({
        icon: 'success',
        title: 'Dados carregados!',
        text: `Aba "${Utils.formatarDataParaAba(dataSelecionada)}" carregada com sucesso`,
        timer: 2000,
        showConfirmButton: false,
        toast: true
      });
    } catch (error) {
      console.error('Erro ao carregar técnicos:', error);
      Swal.fire({
        icon: 'error',
        title: 'Erro',
        text: 'Erro ao carregar dados. Verifique sua conexão.'
      });
    } finally {
      setCarregando(false);
    }
  };

  const toggleTecnico = (tecnico) => {
    const index = tecnicosSelecionados.findIndex(t => t.nome === tecnico.nome && t.regional === tecnico.regional);
    if (index === -1) {
      setTecnicosSelecionados([...tecnicosSelecionados, tecnico]);
    } else {
      setTecnicosSelecionados(tecnicosSelecionados.filter((_, i) => i !== index));
    }
  };

  const selecionarTodosTecnicos = () => {
    setTecnicosSelecionados([...tecnicosPlanilha]);
  };

  const desmarcarTodosTecnicos = () => {
    setTecnicosSelecionados([]);
  };

  const selecionarPorRegional = (regional) => {
    const tecnicosDaRegional = tecnicosPlanilha.filter(t => t.regional === regional);
    setTecnicosSelecionados(tecnicosDaRegional);
  };

  const processarProdutividade = async () => {
    if (!data) {
      Swal.fire({
        icon: 'warning',
        title: 'Selecione uma data',
        text: 'Primeiro selecione a data dos dados!'
      });
      return;
    }

    if (tecnicosSelecionados.length === 0) {
      Swal.fire({
        icon: 'warning',
        title: 'Nenhum técnico selecionado',
        text: 'Selecione pelo menos um técnico da lista!'
      });
      return;
    }

    if (!dadosPlanilha) {
      await carregarTecnicosPorData(data);
      if (!dadosPlanilha) {
        Swal.fire({
          icon: 'warning',
          title: 'Dados não carregados',
          text: 'Não foi possível carregar os dados para esta data!'
        });
        return;
      }
    }

    setCarregando(true);

    Swal.fire({
      title: 'Processando...',
      text: `Calculando produtividade para ${tecnicosSelecionados.length} técnico(s)`,
      allowOutsideClick: false,
      didOpen: () => Swal.showLoading()
    });

    const resultados = [];
    const metricasTotal = {
      planejamento: 0,
      execucao: 0,
      remarcacao: 0,
      cancelamento: 0,
      tratativasCS: 0,
      infraestrutura: 0,
      resolucaoN2: 0,
      totalProdutividade: 0,
      totalExecutado: 0
    };

    for (const tecnicoObj of tecnicosSelecionados) {
      const metricas = PlanilhaProcessor.processarDadosTecnicoPorRegional(
        dadosPlanilha,
        tecnicoObj.nome,
        tecnicoObj.regional,
        { TABELA_PESOS, SERVICOS_IGNORADOS, Utils }
      );

      resultados.push({
        tecnico: tecnicoObj.nome,
        regional: tecnicoObj.regional,
        ...metricas
      });

      metricasTotal.planejamento += metricas.planejamento;
      metricasTotal.execucao += metricas.execucao;
      metricasTotal.remarcacao += metricas.remarcacao;
      metricasTotal.cancelamento += metricas.cancelamento;
      metricasTotal.tratativasCS += metricas.tratativasCS;
      metricasTotal.infraestrutura += metricas.infraestrutura;
      metricasTotal.resolucaoN2 += metricas.resolucaoN2;
      metricasTotal.totalProdutividade += metricas.produtividade;
      metricasTotal.totalExecutado += metricas.totalExecutado;
    }

    setDadosProdutividade(resultados);
    setMetricasAgregadas(metricasTotal);

    // Atualizar gráficos
    atualizarGraficos(resultados, metricasTotal);

    Swal.fire({
      icon: 'success',
      title: 'Processamento concluído!',
      text: `${tecnicosSelecionados.length} técnico(s) processados com sucesso`,
      timer: 3000,
      showConfirmButton: false
    });

    setCarregando(false);
  };

  const atualizarGraficos = (resultados, metricasTotal) => {
    // Gráfico de Barras - Métricas Gerais
    const ctxBar = document.getElementById('metricasGeraisChart')?.getContext('2d');
    if (ctxBar) {
      if (barChartInstance) barChartInstance.destroy();

      barChartInstance = new Chart(ctxBar, {
        type: 'bar',
        data: {
          labels: ['Planejamento', 'Execução', 'Remarcação', 'Cancelamento', 'Tratativas CS', 'Infraestrutura', 'Resolução N2'],
          datasets: [{
            label: 'Quantidade de Protocolos',
            data: [
              metricasTotal.planejamento,
              metricasTotal.execucao,
              metricasTotal.remarcacao,
              metricasTotal.cancelamento,
              metricasTotal.tratativasCS,
              metricasTotal.infraestrutura,
              metricasTotal.resolucaoN2
            ],
            backgroundColor: 'rgba(232, 70, 93, 0.8)',
            borderColor: '#E8465D',
            borderWidth: 2,
            borderRadius: 12,
            barPercentage: 0.7
          }]
        },
        options: {
          responsive: true,
          maintainAspectRatio: true,
          plugins: {
            legend: { position: 'top', labels: { font: { size: 12 } } },
            tooltip: {
              callbacks: {
                label: (ctx) => `${ctx.raw} protocolos`
              }
            }
          },
          scales: {
            y: { beginAtZero: true, grid: { color: 'rgba(0,0,0,0.05)' } },
            x: { ticks: { maxRotation: 35, minRotation: 35, font: { size: 10 } } }
          }
        }
      });
    }

    // Gráfico de Pizza - Distribuição
    const ctxPie = document.getElementById('distribuicaoChart')?.getContext('2d');
    if (ctxPie) {
      if (pieChartInstance) pieChartInstance.destroy();

      const labelsPie = ['Planejamento', 'Execução', 'Remarcação', 'Cancelamento', 'Tratativas CS', 'Infraestrutura', 'Resolução N2'];
      const valoresPie = [
        metricasTotal.planejamento,
        metricasTotal.execucao,
        metricasTotal.remarcacao,
        metricasTotal.cancelamento,
        metricasTotal.tratativasCS,
        metricasTotal.infraestrutura,
        metricasTotal.resolucaoN2
      ];
      const cores = [
        '#E8465D', '#28a745', '#ffc107', '#dc3545', '#17a2b8', '#6f42c1', '#fd7e14'
      ];

      pieChartInstance = new Chart(ctxPie, {
        type: 'doughnut',
        data: {
          labels: labelsPie,
          datasets: [{
            data: valoresPie,
            backgroundColor: cores,
            borderWidth: 0,
            cutout: '60%'
          }]
        },
        options: {
          responsive: true,
          maintainAspectRatio: true,
          plugins: {
            legend: { position: 'right', labels: { font: { size: 10 } } },
            tooltip: {
              callbacks: {
                label: (ctx) => {
                  const total = valoresPie.reduce((a, b) => a + b, 0);
                  const percent = total > 0 ? ((ctx.raw / total) * 100).toFixed(1) : 0;
                  return `${ctx.label}: ${ctx.raw} (${percent}%)`;
                }
              }
            }
          }
        }
      });
    }

    // Gráfico de Barras - Produtividade por Técnico
    const ctxTecnicos = document.getElementById('produtividadeTecnicosChart')?.getContext('2d');
    if (ctxTecnicos && resultados.length > 0) {
      if (tecnicosChartInstance) tecnicosChartInstance.destroy();

      const tecnicosNomes = resultados.map(r => r.tecnico.split(' ').pop() || r.tecnico.substring(0, 12));
      const produtividades = resultados.map(r => r.produtividade);
      const executados = resultados.map(r => r.totalExecutado);

      tecnicosChartInstance = new Chart(ctxTecnicos, {
        type: 'bar',
        data: {
          labels: tecnicosNomes,
          datasets: [
            {
              label: 'Produtividade',
              data: produtividades,
              backgroundColor: 'rgba(232, 70, 93, 0.8)',
              borderRadius: 8,
              yAxisID: 'y'
            },
            {
              label: 'Serviços Executados',
              data: executados,
              backgroundColor: 'rgba(40, 167, 69, 0.8)',
              borderRadius: 8,
              yAxisID: 'y'
            }
          ]
        },
        options: {
          responsive: true,
          maintainAspectRatio: true,
          plugins: {
            legend: { position: 'top', labels: { font: { size: 10 } } },
            tooltip: {
              callbacks: {
                label: (ctx) => `${ctx.dataset.label}: ${ctx.raw.toFixed(2)}`
              }
            }
          },
          scales: {
            y: { beginAtZero: true, title: { display: true, text: 'Pontos', font: { size: 10 } } },
            x: { ticks: { maxRotation: 45, minRotation: 45, font: { size: 9 } } }
          }
        }
      });
    }
  };

  const exportarResultados = () => {
    if (dadosProdutividade.length === 0) {
      Swal.fire({
        icon: 'warning',
        title: 'Nenhum dado',
        text: 'Processe os técnicos primeiro!',
        toast: true,
        timer: 2000
      });
      return;
    }

    let csvContent = 'Técnico,Regional,Planejamento,Execução,Remarcação,Cancelamento,Tratativas CS,Infraestrutura,Resolução N2,Total Executado,Produtividade\n';

    dadosProdutividade.forEach(item => {
      csvContent += `"${item.tecnico}",${item.regional},${item.planejamento},${item.execucao},${item.remarcacao},${item.cancelamento},${item.tratativasCS},${item.infraestrutura},${item.resolucaoN2},${item.totalExecutado},${item.produtividade.toFixed(2)}\n`;
    });

    csvContent += '\n"TOTAIS GERAL",,';
    csvContent += `${metricasAgregadas.planejamento},${metricasAgregadas.execucao},${metricasAgregadas.remarcacao},${metricasAgregadas.cancelamento},${metricasAgregadas.tratativasCS},${metricasAgregadas.infraestrutura},${metricasAgregadas.resolucaoN2},${metricasAgregadas.totalExecutado},${metricasAgregadas.totalProdutividade.toFixed(2)}\n`;

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `produtividade_${Utils.formatarData(data)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

    Swal.fire({
      icon: 'success',
      title: 'Exportado!',
      text: 'Arquivo CSV gerado com sucesso',
      toast: true,
      timer: 2000
    });
  };

  const getTecnicosPorRegional = (regional) => {
    if (regional === 'todas') return tecnicosPlanilha;
    return tecnicosPlanilha.filter(t => t.regional === regional);
  };

  const tecnicosFiltrados = getTecnicosPorRegional(filtroRegional);
  const tecnicosExibicao = buscaTermo
    ? tecnicosFiltrados.filter(t => t.nome.toLowerCase().includes(buscaTermo.toLowerCase()))
    : tecnicosFiltrados;

  const regionaisLista = ['todas', ...Object.keys(regionais)];

  // Agrupar técnicos selecionados por regional
  const tecnicosSelecionadosAgrupados = {};
  tecnicosSelecionados.forEach(tec => {
    if (!tecnicosSelecionadosAgrupados[tec.regional]) {
      tecnicosSelecionadosAgrupados[tec.regional] = [];
    }
    tecnicosSelecionadosAgrupados[tec.regional].push(tec);
  });

  return (
    <div id="aba-produtividade" className="aba-conteudo ativo">
      {/* Card de Filtros */}
      <div className="card-produtividade">
        <div className="card-header-produtividade">
          <h3><i className="fas fa-chart-line"></i> Produtividade por Técnico</h3>
          <p className="card-subtitle">Selecione os técnicos e visualize as métricas de produtividade</p>
        </div>

        <div className="filtros-row">
          <div className="filtro-group">
            <label><i className="far fa-calendar-alt"></i> Data</label>
            <input
              type="date"
              value={data}
              onChange={(e) => setData(e.target.value)}
              className="input-moderno"
            />
          </div>
          <div className="filtro-group">
            <label><i className="fas fa-filter"></i> Filtrar por Regional</label>
            <select
              value={filtroRegional}
              onChange={(e) => setFiltroRegional(e.target.value)}
              className="input-moderno"
            >
              {regionaisLista.map(reg => (
                <option key={reg} value={reg}>
                  {reg === 'todas' ? 'Todas as Regionais' : reg}
                </option>
              ))}
            </select>
          </div>
          <div className="filtro-group">
            <label><i className="fas fa-search"></i> Buscar Técnico</label>
            <input
              type="text"
              placeholder="Digite o nome..."
              value={buscaTermo}
              onChange={(e) => setBuscaTermo(e.target.value)}
              className="input-moderno"
            />
          </div>
        </div>

        <div className="tecnicos-buttons">
          <button onClick={selecionarTodosTecnicos} className="btn-outline-primary">
            <i className="fas fa-check-double"></i> Selecionar Todos
          </button>
          <button onClick={desmarcarTodosTecnicos} className="btn-outline-secondary">
            <i className="fas fa-times"></i> Desmarcar Todos
          </button>
          {regionaisLista.filter(r => r !== 'todas').map(reg => (
            <button key={reg} onClick={() => selecionarPorRegional(reg)} className="btn-outline-regional">
              <i className="fas fa-map-marker-alt"></i> {reg}
            </button>
          ))}
        </div>
      </div>

      {/* Duas colunas: Técnicos da Planilha e Técnicos Selecionados */}
      <div className="tecnicos-duas-colunas">
        <div className="coluna-tecnicos">
          <div className="card-lista">
            <div className="card-header-lista">
              <h4><i className="fas fa-users"></i> Técnicos da Planilha</h4>
              <span className="badge-count">{tecnicosExibicao.length} técnicos</span>
            </div>
            <div className="tecnicos-lista-scroll">
              {carregando ? (
                <div className="loading-placeholder">
                  <i className="fas fa-spinner fa-pulse"></i> Carregando técnicos...
                </div>
              ) : tecnicosExibicao.length === 0 ? (
                <div className="empty-placeholder">
                  <i className="fas fa-search"></i> Nenhum técnico encontrado
                </div>
              ) : (
                tecnicosExibicao.map(tec => {
                  const isSelected = tecnicosSelecionados.some(t => t.nome === tec.nome && t.regional === tec.regional);
                  return (
                    <div
                      key={`${tec.nome}-${tec.regional}`}
                      className={`tecnico-item ${isSelected ? 'selected' : ''}`}
                      onClick={() => toggleTecnico(tec)}
                    >
                      <input
                        type="checkbox"
                        checked={isSelected}
                        onChange={() => {}}
                      />
                      <div className="tecnico-info">
                        <span className="tecnico-nome">{tec.nome}</span>
                        <span className="tecnico-regional">{tec.regional}</span>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>

        <div className="coluna-selecionados">
          <div className="card-lista">
            <div className="card-header-lista">
              <h4><i className="fas fa-check-circle"></i> Técnicos Selecionados</h4>
              <span className="badge-count-selected">{tecnicosSelecionados.length} técnicos</span>
            </div>
            <div className="tecnicos-selecionados-scroll">
              {tecnicosSelecionados.length === 0 ? (
                <div className="empty-placeholder-selected">
                  <i className="fas fa-user-plus"></i> Selecione técnicos ao lado
                </div>
              ) : (
                Object.entries(tecnicosSelecionadosAgrupados).map(([regional, tecnicos]) => (
                  <div key={regional} className="regional-selecionada">
                    <div className="regional-titulo-selecionada">
                      <i className="fas fa-map-marker-alt"></i>
                      <span>{regional}</span>
                      <span className="contador">{tecnicos.length}</span>
                    </div>
                    <div className="tecnicos-selecionados-lista">
                      {tecnicos.map(tec => (
                        <div key={tec.nome} className="tecnico-selecionado-item">
                          <i className="fas fa-user"></i>
                          <span>{tec.nome}</span>
                          <button
                            className="btn-remove-tecnico"
                            onClick={() => toggleTecnico(tec)}
                          >
                            <i className="fas fa-times-circle"></i>
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                ))
              )}
            </div>
            <div className="card-footer-actions">
              <button
                onClick={processarProdutividade}
                className="btn-processar"
                disabled={carregando || tecnicosSelecionados.length === 0}
              >
                <i className="fas fa-chart-simple"></i>
                {carregando ? 'Processando...' : 'Processar Produtividade'}
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Cards de Resumo */}
      {dadosProdutividade.length > 0 && (
        <>
          <div className="summary-cards-produtividade">
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#E8465D20' }}>
                <i className="fas fa-tasks" style={{ color: '#E8465D' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.planejamento + metricasAgregadas.execucao + metricasAgregadas.remarcacao + metricasAgregadas.cancelamento + metricasAgregadas.tratativasCS + metricasAgregadas.infraestrutura + metricasAgregadas.resolucaoN2}</h3>
                <p>Total de Protocolos</p>
              </div>
            </div>
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#28a74520' }}>
                <i className="fas fa-check-circle" style={{ color: '#28a745' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.execucao}</h3>
                <p>Protocolos Executados</p>
              </div>
            </div>
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#ffc10720' }}>
                <i className="fas fa-chart-line" style={{ color: '#ffc107' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.totalProdutividade.toFixed(2)}</h3>
                <p>Produtividade Total</p>
              </div>
            </div>
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#17a2b820' }}>
                <i className="fas fa-exchange-alt" style={{ color: '#17a2b8' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.remarcacao}</h3>
                <p>Remarcações</p>
              </div>
            </div>
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#dc354520' }}>
                <i className="fas fa-ban" style={{ color: '#dc3545' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.cancelamento}</h3>
                <p>Cancelamentos</p>
              </div>
            </div>
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#6f42c120' }}>
                <i className="fas fa-headset" style={{ color: '#6f42c1' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.tratativasCS}</h3>
                <p>Tratativas CS</p>
              </div>
            </div>
            <div className="summary-card-prod">
              <div className="card-icon-prod" style={{ background: '#fd7e1420' }}>
                <i className="fas fa-microchip" style={{ color: '#fd7e14' }}></i>
              </div>
              <div className="card-info-prod">
                <h3>{metricasAgregadas.resolucaoN2}</h3>
                <p>Resolução N2</p>
              </div>
            </div>
          </div>

          {/* Gráficos */}
          <div className="charts-grid-produtividade">
            <div className="chart-card-prod">
              <div className="chart-header-prod">
                <i className="fas fa-chart-bar"></i>
                <h4>Métricas por Tipo</h4>
              </div>
              <canvas id="metricasGeraisChart" height="280"></canvas>
            </div>
            <div className="chart-card-prod">
              <div className="chart-header-prod">
                <i className="fas fa-chart-pie"></i>
                <h4>Distribuição Percentual</h4>
              </div>
              <canvas id="distribuicaoChart" height="280"></canvas>
            </div>
            <div className="chart-card-prod chart-full-width">
              <div className="chart-header-prod">
                <i className="fas fa-trophy"></i>
                <h4>Produtividade por Técnico</h4>
              </div>
              <canvas id="produtividadeTecnicosChart" height="300"></canvas>
            </div>
          </div>

          {/* Tabela de Resultados */}
          <div className="tabela-resultados-prod">
            <div className="tabela-header">
              <h4><i className="fas fa-table"></i> Detalhamento por Técnico</h4>
              <button onClick={exportarResultados} className="btn-exportar">
                <i className="fas fa-file-excel"></i> Exportar CSV
              </button>
            </div>
            <div className="table-responsive">
              <table className="data-table-prod">
                <thead>
                  <tr>
                    <th>Técnico</th>
                    <th>Regional</th>
                    <th>Planej.</th>
                    <th>Exec.</th>
                    <th>Remarc.</th>
                    <th>Cancel.</th>
                    <th>Trat. CS</th>
                    <th>Infra.</th>
                    <th>Res. N2</th>
                    <th>Total Exec.</th>
                    <th>Produtividade</th>
                  </tr>
                </thead>
                <tbody>
                  {dadosProdutividade.map((item, idx) => (
                    <tr key={idx}>
                      <td><strong>{item.tecnico}</strong></td>
                      <td>{item.regional}</td>
                      <td>{item.planejamento}</td>
                      <td>{item.execucao}</td>
                      <td>{item.remarcacao}</td>
                      <td>{item.cancelamento}</td>
                      <td>{item.tratativasCS}</td>
                      <td>{item.infraestrutura}</td>
                      <td>{item.resolucaoN2}</td>
                      <td>{item.totalExecutado}</td>
                      <td className="produtividade-destaque">{item.produtividade.toFixed(2)}</td>
                    </tr>
                  ))}
                  <tr className="total-row">
                    <td colSpan="2"><strong>TOTAIS</strong></td>
                    <td><strong>{metricasAgregadas.planejamento}</strong></td>
                    <td><strong>{metricasAgregadas.execucao}</strong></td>
                    <td><strong>{metricasAgregadas.remarcacao}</strong></td>
                    <td><strong>{metricasAgregadas.cancelamento}</strong></td>
                    <td><strong>{metricasAgregadas.tratativasCS}</strong></td>
                    <td><strong>{metricasAgregadas.infraestrutura}</strong></td>
                    <td><strong>{metricasAgregadas.resolucaoN2}</strong></td>
                    <td><strong>{metricasAgregadas.totalExecutado}</strong></td>
                    <td className="produtividade-destaque"><strong>{metricasAgregadas.totalProdutividade.toFixed(2)}</strong></td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default AbaProdutividade;
